--
-- Table structure for table `host_exec_log`
--

DROP TABLE IF EXISTS `host_exec_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `host_exec_log` (
  `id` bigint NOT NULL COMMENT '主键',
  `host_id` bigint DEFAULT NULL COMMENT '主机主键;host_rec 表主键',
  `user_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行用户',
  `tc_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行测试 id',
  `cycle_name` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '周期名称',
  `user_name` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户名称',
  `err_msg` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '异常信息',
  `begin_time` datetime DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `host_state` tinyint DEFAULT NULL COMMENT '主机状态;{free: 0, 空闲. lock: 1, 已锁定. occ: 2, 已占用. run: 3, case执行中.offline: 4, 离线.}',
  `case_state` tinyint DEFAULT '0' COMMENT 'case 执行状态;{free: 0, 空闲. start: 1, 启动. success: 2, 成功. failed: 3, 失败.}',
  `result_msg` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行结果',
  `log_url` varchar(512) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行日志 log 地址',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `exec_rmk` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注信息',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `updated_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint NOT NULL DEFAULT '0' COMMENT '删除标识;{useing: 0, 使用中. del: 1, 删除.}',
  PRIMARY KEY (`id`),
  KEY `ix_host` (`host_id`),
  KEY `ix_hs` (`host_state`),
  KEY `ix_ct` (`created_time`),
  KEY `ix_del` (`del_flag`),
  KEY `ix_user` (`user_id`),
  KEY `ix_case_state` (`case_state`),
  KEY `ix_host_case_begin_del` (`host_state`,`case_state`,`begin_time`,`del_flag`),
  CONSTRAINT `host_exec_log_chk_1` CHECK (json_valid(`err_msg`))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='主机执行日志';
/*!40101 SET character_set_client = @saved_cs_client */;

