--
-- Table structure for table `host_hw_rec`
--

DROP TABLE IF EXISTS `host_hw_rec`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `host_hw_rec` (
  `id` bigint NOT NULL COMMENT '主键',
  `hardware_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'mongodb 主键;mongo db 硬件 id',
  `host_id` bigint DEFAULT NULL COMMENT '主机主键;host_rec 表主键',
  `hw_info` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '硬件信息;mongo db 数据格式',
  `diff_state` tinyint DEFAULT NULL COMMENT '参数状态;{ver_diff: 1, 版本号变化. item_diff: 2, 内容更改. failed: 3, 异常.}',
  `sync_state` tinyint DEFAULT '0' COMMENT '同步状态;{empty: 0 空状态. wait: 1, 待同步. success: 2, 通过. failed: 3, 异常.}',
  `appr_time` datetime DEFAULT NULL COMMENT '审批时间',
  `appr_by` bigint DEFAULT NULL COMMENT '审批人',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `updated_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint NOT NULL DEFAULT '0' COMMENT '删除标识;{useing: 0, 使用中. del: 1, 删除.}',
  `hw_ver` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '硬件版本号',
  PRIMARY KEY (`id`),
  KEY `ix_host` (`host_id`),
  KEY `ix_ct` (`created_time`),
  KEY `ix_del` (`del_flag`),
  KEY `ix_sync_state` (`sync_state`,`del_flag`),
  KEY `ix_diff_state` (`diff_state`,`del_flag`),
  KEY `ix_host_sync_diff_del` (`host_id`,`sync_state`,`diff_state`,`del_flag`),
  CONSTRAINT `host_hw_rec_chk_1` CHECK (json_valid(`hw_info`))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='主机硬件记录;记录主机硬件变动信息';
/*!40101 SET character_set_client = @saved_cs_client */;

