--
-- Table structure for table `host_rec`
--

DROP TABLE IF EXISTS `host_rec`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `host_rec` (
  `id` bigint NOT NULL COMMENT '主键',
  `host_no` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主机主键;对应 mongo 数据库 host 主键',
  `mg_id` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '唯一引导id',
  `host_ip` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'ip 地址',
  `host_port` int DEFAULT NULL COMMENT 'ip 端口',
  `host_acct` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主机账号',
  `host_pwd` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主机密码',
  `mac_addr` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'mac 地址',
  `appr_state` tinyint DEFAULT NULL COMMENT '审批状态;{disable: 0, 停用. enable: 1, 启用. new: 2, 新增. change: 3, 存在改动.}',
  `host_state` tinyint DEFAULT NULL COMMENT '主机状态;{free: 0, 空闲. lock: 1, 已锁定. occ: 2, 已占用. run: 3, case执行中.offline: 4, 离线. inact: 5, 待激活. hw_chg: 6, 存在潜在的硬件改动. disable: 7, 手动停用. updating: 8, 更新中.}',
  `subm_time` datetime DEFAULT NULL COMMENT '申报时间',
  `hw_id` bigint DEFAULT NULL COMMENT '硬件记录表主键;host_hw_rec 表主键',
  `agent_ver` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'agent 版本号',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `updated_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint NOT NULL DEFAULT '0' COMMENT '删除标识;{useing: 0, 使用中. del: 1, 删除.}',
  `hardware_id` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'mongodb 主键;mongo db 硬件 id',
  `tcp_state` tinyint DEFAULT NULL COMMENT 'tcp在线状态;{close: 0, 关闭.  wait: 1, 等待. lsn: 2, 监听.}',
  PRIMARY KEY (`id`),
  KEY `ix_host` (`host_no`),
  KEY `ix_mg` (`mg_id`),
  KEY `ix_as` (`appr_state`),
  KEY `ix_mac` (`mac_addr`),
  KEY `ix_del` (`del_flag`),
  KEY `ix_st` (`subm_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='主机记录;host 列表，记录硬件变动信息';
/*!40101 SET character_set_client = @saved_cs_client */;

