DROP TABLE IF EXISTS `sys_menu`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_menu` (
  `id` bigint NOT NULL COMMENT '主键',
  `parent_id` bigint DEFAULT NULL COMMENT '父级主键',
  `menu_type` tinyint NOT NULL COMMENT '菜单类型;{dir: 1, 目录. menu: 2, 菜单. button: 3, 按钮.}',
  `menu_perm` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单权限;菜单下所有接口url逗号拼接',
  `menu_compo_name` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'VUE自定义组件名称',
  `menu_title` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单标题 i18n code',
  `menu_name` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单名称支持i8n',
  `menu_path` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单路由地址',
  `menu_redirect` varchar(32) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '转发地址',
  `menu_compo_path` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单组件路径目录及为LAYOUT',
  `menu_icon` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '菜单图标',
  `menu_affix` varchar(1) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标签是否固定;{default: "", 默认空. true: "1", 固定. false: "0", 不固定.}',
  `keep_alive` varchar(1) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'KeepAlive缓存，默认为空;KeepAlive缓存，默认为空',
  `link_flag` tinyint DEFAULT NULL COMMENT '链接标识，默认为空;{no: 0, 不是链接类型菜单. yes: 1, 是链接类型菜单.}',
  `show_menu` tinyint DEFAULT NULL COMMENT '显示菜单，默认为空;{no: 0, 不显示. yes: 1, 显示.}',
  `hide_menu` tinyint DEFAULT NULL COMMENT '隐藏菜单，默认为空;{no: 0, 不隐藏. yes: 1, 隐藏.}',
  `hide_childrenin_menu` tinyint DEFAULT NULL COMMENT '显示子集菜单;{no: 0, 不显示. yes: 1, 显示.}',
  `current_active_menu` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '当前活动菜单',
  `hide_breadcrumb` tinyint DEFAULT NULL COMMENT '动态添加路由，默认为空;{no: 0, 否. yes: 1, 是.}',
  `sort_num` int DEFAULT NULL COMMENT '排序编号',
  `data_flag` tinyint DEFAULT NULL COMMENT '状态标识;{not_use: 0, 停用. useing: 1, 使用中.}',
  `del_flag` tinyint NOT NULL COMMENT '删除标识;{useing: 0, 使用中. del: 1, 删除.}',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `updated_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `ix_sys_menu_del` (`del_flag`),
  KEY `ix_sys_menu_state` (`data_flag`),
  KEY `ix_sys_menu_type` (`menu_type`),
  KEY `ix_tx` (`created_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='菜单表';
